#import "TPSettingsEntryView.h"
#import "TPThemeAdapter.h"
@implementation TPSettingsEntryView
-(instancetype)initWithFrame:(CGRect)f{if((self=[super initWithFrame:f])){self.backgroundColor=TPThemeAdapter.cellBackground;UIImageView*icon=[[UIImageView alloc]initWithFrame:CGRectMake(18,17,30,30)];if(@available(iOS 13,*))icon.image=[UIImage systemImageNamed:@"globe"];icon.tintColor=TPThemeAdapter.accent;[self addSubview:icon];UILabel*title=[[UILabel alloc]initWithFrame:CGRectMake(62,10,240,24)];title.text=@"翻译插件设置";title.font=[UIFont systemFontOfSize:16];title.textColor=TPThemeAdapter.primaryText;[self addSubview:title];UILabel*sub=[[UILabel alloc]initWithFrame:CGRectMake(62,34,240,20)];sub.text=@"自动翻译、API、术语库";sub.font=[UIFont systemFontOfSize:12];sub.textColor=TPThemeAdapter.secondaryText;[self addSubview:sub];UILabel*arrow=[[UILabel alloc]initWithFrame:CGRectMake(CGRectGetWidth(f)-32,20,18,24)];arrow.text=@"›";arrow.font=[UIFont systemFontOfSize:25];arrow.textColor=TPThemeAdapter.secondaryText;arrow.autoresizingMask=UIViewAutoresizingFlexibleLeftMargin;[self addSubview:arrow];UIView*line=[[UIView alloc]initWithFrame:CGRectMake(62,63,CGRectGetWidth(f)-62,0.5)];line.backgroundColor=[UIColor colorWithWhite:.5 alpha:.25];line.autoresizingMask=UIViewAutoresizingFlexibleWidth;[self addSubview:line];self.accessibilityLabel=@"翻译插件设置，自动翻译、API、术语库";self.accessibilityTraits=UIAccessibilityTraitButton;}return self;}
@end
